update public.activities as activity
set
  start_time = schedule_updates.start_time,
  end_time = schedule_updates.end_time,
  days_of_week = schedule_updates.days,
  available_days_of_week = schedule_updates.days,
  availability_type = 'weekly',
  availability_notes = schedule_updates.availability_notes,
  schedule_notes = schedule_updates.availability_notes,
  age_suitability = coalesce(schedule_updates.age_suitability, activity.age_suitability),
  cost = coalesce(schedule_updates.cost, activity.cost),
  description = coalesce(schedule_updates.description, activity.description),
  website = schedule_updates.source_url,
  image_url = coalesce(activity.google_photo_url, activity.image_url, schedule_updates.image_url),
  image_source_url = case when activity.google_photo_url is null and activity.image_url is null then schedule_updates.source_url else activity.image_source_url end,
  updated_at = now()
from schedule_updates
where lower(trim(trailing '/' from activity.source_url)) = lower(trim(trailing '/' from schedule_updates.source_url));
